import express from 'express';
import fs from 'fs/promises';
import path from 'path';
import { createServer as createViteServer } from 'vite';

const DATABASE_DIR = path.join(process.cwd(), 'data');
const DATABASE_FILE = path.join(DATABASE_DIR, 'armeria_db.json');
const SERVER_STATE_ENDPOINT = '/api/state';

async function ensureDatabaseDir() {
  await fs.mkdir(DATABASE_DIR, { recursive: true });
}

async function readServerState() {
  try {
    const stateJson = await fs.readFile(DATABASE_FILE, 'utf8');
    return JSON.parse(stateJson);
  } catch (error: any) {
    if (error.code === 'ENOENT') {
      return null;
    }
    console.error('Failed to read server state:', error);
    return null;
  }
}

async function writeServerState(state: unknown) {
  try {
    await ensureDatabaseDir();
    await fs.writeFile(DATABASE_FILE, JSON.stringify(state, null, 2), 'utf8');
  } catch (error) {
    console.error('Failed to write server state:', error);
  }
}

async function startServer() {
  const app = express();
  const PORT = 3000;

  app.use(express.json());

  // API Routes
  app.get('/api/health', (req, res) => {
    res.json({ status: 'ok', app: 'Armeria - Gestão de Armas e Munições' });
  });

  app.get(SERVER_STATE_ENDPOINT, async (req, res) => {
    const state = await readServerState();
    if (!state) {
      return res.status(404).json({ message: 'Server state not initialized' });
    }
    return res.json(state);
  });

  app.post(SERVER_STATE_ENDPOINT, async (req, res) => {
    const state = req.body;
    await writeServerState(state);
    return res.json({ success: true });
  });

  const ENTITY_MAP: Record<string, string> = {
    users: 'users',
    departments: 'departments',
    units: 'units',
    courses: 'courses',
    vaultspaces: 'vaultSpaces',
    'vault-spaces': 'vaultSpaces',
    calibers: 'calibers',
    'ammo-stocks': 'ammoStocks',
    'ammo-movements': 'ammoMovements',
    weapons: 'weapons',
    movements: 'movements',
    'audit-logs': 'auditLogs',
    auditlogs: 'auditLogs'
  };

  function resolveEntityKey(entityParam: string) {
    return ENTITY_MAP[entityParam.toLowerCase()];
  }

  app.get('/api/:entity', async (req, res) => {
    const entityKey = resolveEntityKey(req.params.entity);
    if (!entityKey) {
      return res.status(404).json({ error: 'Entity not found' });
    }

    const state = await readServerState();
    if (!state) {
      return res.status(404).json({ error: 'Server state not initialized' });
    }

    const entityData = (state as any)[entityKey];
    if (!Array.isArray(entityData)) {
      return res.status(404).json({ error: 'Entity data not available' });
    }

    return res.json(entityData);
  });

  app.get('/api/:entity/:id', async (req, res) => {
    const entityKey = resolveEntityKey(req.params.entity);
    if (!entityKey) {
      return res.status(404).json({ error: 'Entity not found' });
    }

    const state = await readServerState();
    if (!state) {
      return res.status(404).json({ error: 'Server state not initialized' });
    }

    const entityData = (state as any)[entityKey];
    if (!Array.isArray(entityData)) {
      return res.status(404).json({ error: 'Entity data not available' });
    }

    const item = entityData.find((entry: any) => entry.id === req.params.id);
    if (!item) {
      return res.status(404).json({ error: 'Item not found' });
    }

    return res.json(item);
  });

  app.post('/api/:entity', async (req, res) => {
    const entityKey = resolveEntityKey(req.params.entity);
    if (!entityKey) {
      return res.status(404).json({ error: 'Entity not found' });
    }

    const state = await readServerState();
    if (!state) {
      return res.status(404).json({ error: 'Server state not initialized' });
    }

    const entityData = (state as any)[entityKey];
    if (!Array.isArray(entityData)) {
      return res.status(404).json({ error: 'Entity data not available' });
    }

    const item = req.body;
    if (!item || typeof item !== 'object') {
      return res.status(400).json({ error: 'Invalid payload' });
    }

    if (!item.id) {
      item.id = `${req.params.entity}-${Date.now()}`;
    }

    entityData.push(item);
    await writeServerState(state);
    return res.status(201).json(item);
  });

  app.put('/api/:entity/:id', async (req, res) => {
    const entityKey = resolveEntityKey(req.params.entity);
    if (!entityKey) {
      return res.status(404).json({ error: 'Entity not found' });
    }

    const state = await readServerState();
    if (!state) {
      return res.status(404).json({ error: 'Server state not initialized' });
    }

    const entityData = (state as any)[entityKey];
    if (!Array.isArray(entityData)) {
      return res.status(404).json({ error: 'Entity data not available' });
    }

    const index = entityData.findIndex((entry: any) => entry.id === req.params.id);
    if (index === -1) {
      return res.status(404).json({ error: 'Item not found' });
    }

    const updates = req.body;
    if (!updates || typeof updates !== 'object') {
      return res.status(400).json({ error: 'Invalid payload' });
    }

    entityData[index] = { ...entityData[index], ...updates, id: req.params.id };
    await writeServerState(state);
    return res.json(entityData[index]);
  });

  app.put('/api/:entity', async (req, res) => {
    const entityKey = resolveEntityKey(req.params.entity);
    if (!entityKey) {
      return res.status(404).json({ error: 'Entity not found' });
    }

    const state = await readServerState();
    if (!state) {
      return res.status(404).json({ error: 'Server state not initialized' });
    }

    const payload = req.body;
    if (!Array.isArray(payload)) {
      return res.status(400).json({ error: 'Payload must be an array' });
    }

    (state as any)[entityKey] = payload;
    await writeServerState(state);
    return res.json(payload);
  });

  app.delete('/api/:entity/:id', async (req, res) => {
    const entityKey = resolveEntityKey(req.params.entity);
    if (!entityKey) {
      return res.status(404).json({ error: 'Entity not found' });
    }

    const state = await readServerState();
    if (!state) {
      return res.status(404).json({ error: 'Server state not initialized' });
    }

    const entityData = (state as any)[entityKey];
    if (!Array.isArray(entityData)) {
      return res.status(404).json({ error: 'Entity data not available' });
    }

    const index = entityData.findIndex((entry: any) => entry.id === req.params.id);
    if (index === -1) {
      return res.status(404).json({ error: 'Item not found' });
    }

    entityData.splice(index, 1);
    await writeServerState(state);
    return res.json({ success: true });
  });

  // Vite middleware for development vs static serve for production
  if (process.env.NODE_ENV !== 'production') {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: 'spa',
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, '0.0.0.0', () => {
    console.log(`[Armeria] Server running on http://0.0.0.0:${PORT}`);
  });
}

startServer();
